fn solve(nums: Vec<i64>) -> i64 {
    let mut count = 0;
    let n = nums.len();

    for i in 0..n {
        for j in i+1..n {
            let a = nums[i];
            let b = nums[j];
            let abs_a = a.abs();
            let abs_b = b.abs();
            let min_ab = abs_a.min(abs_b);
            let max_ab = abs_a.max(abs_b);

            let diff = (a - b).abs();
            let sum = (a + b).abs();
